export const getBySlug = (slug: string) => registry.find(a => a.slug === slug) ?? null
export const getByCategory = (cat: AppCategory) => registry.filter(a => a.category === cat)
export const getFeatured = () => registry.filter(a => a.featured)

// For client components - export versions without the load function (which can't be serialized)
export const getClientRegistry = () =>
  registry.map(({ load, ...app }) => app)

export const getClientBySlug = (slug: string) => {
  const app = getBySlug(slug)
  if (!app) return null
  const { load, ...rest } = app
  return rest
}

export const getClientByCategory = (cat: AppCategory) =>
  getByCategory(cat).map(({ load, ...app }) => app)

export const getClientFeatured = () =>
  getFeatured().map(({ load, ...app }) => app)
